/**
 * @param {string} mapData
 * @returns {Record<string, number>}
 */
function unpack(mapData) {
    const decompressed = strFromU8(gunzipSync(strToU8(atob(mapData), true)));
    // parse: ("34599:2,34600:6,..." → { "34599": 2, ... })
    return decompressed.split(",").reduce((acc, entry) => {
        const [k, v] = entry.split(":");
        acc[k] = +v;
        return acc;
    }, /** @type {Record<string, number>} */ ({}));
}
/**
 * skin icon size is 64x64
 *
 * @example
 * // usage:
 * import { SkinMap } from "eve-skin-icons";
 * const iconName = SkinMap[typeId];
 * if (iconName) return `./images/skin-icons/${iconName}.png`;
 * else {
 *   // ...
 * }
 *
 * async function load() {
 *   console.time("load");
 *   const { SkinMap } = await import("./dist/skin-map-compress.js");
 *   console.timeEnd("load");
 *   return SkinMap;
 * }
 * const map = await load();
 * // load: 52.358ms
 * const map2 = await load();
 * // load: 0.765ms -> Subsequent calls are incredibly fast since the module is already cached.
 */
export const SkinMap = unpack(mapData);
